import React, { useState } from 'react';
import axios from 'axios';
import Dropzone from 'react-dropzone';
import './App.css';

function App() {
  const [file, setFile] = useState(null);
  const [targetColumn, setTargetColumn] = useState('diagnosis');
  const [dropColumns, setDropColumns] = useState('id');
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const onDrop = (acceptedFiles) => {
    setFile(acceptedFiles[0]);
    setError(''); // Clear any previous errors
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setError('Please select a CSV file');
      return;
    }

    setLoading(true);
    setError('');
    setResults(null);

    const formData = new FormData();
    formData.append('file', file);
    formData.append('targetColumn', targetColumn);
    formData.append('dropColumns', dropColumns);

    try {
      const response = await axios.post('http://localhost:5000/predict', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
      setResults(response.data.results);
    } catch (err) {
      setError(err.response?.data?.error || 'Network Error: Could not connect to the server');
    } finally {
      setLoading(false);
    }
  };

  const parseResults = (resultsText) => {
    if (!resultsText) return { accuracies: [], bestModel: '', bestAccuracy: 0 };

    const lines = resultsText.split('\n');
    const accuracies = [];
    let bestModel = '';
    let bestAccuracy = 0;

    lines.forEach((line) => {
      if (line.includes('Accuracy:')) {
        const [name, rest] = line.split(' Accuracy: ');
        accuracies.push({ name, accuracy: parseFloat(rest) });
      } else if (line.includes('Error:')) {
        const [name, rest] = line.split(' Error: ');
        accuracies.push({ name, accuracy: 'Error', error: rest });
      } else if (line.includes('Best Model:')) {
        const parts = line.split('Best Model: ')[1].split(' with Accuracy: ');
        bestModel = parts[0];
        bestAccuracy = parseFloat(parts[1]);
      }
    });

    return { accuracies, bestModel, bestAccuracy };
  };

  const { accuracies, bestModel, bestAccuracy } = parseResults(results);

  return (
    <div className="app-container">
      <header className="app-header">
        <h1>Machine Learning Classifier</h1>
        <p>Upload a CSV file to compare multiple ML models</p>
      </header>

      <main className="app-main">
        <form onSubmit={handleSubmit} className="input-form">
          <div className="form-group">
            <label>File Upload</label>
            <Dropzone
              onDrop={onDrop}
              accept={{ 'text/csv': ['.csv'] }}
              multiple={false}
            >
              {({ getRootProps, getInputProps }) => (
                <div {...getRootProps()} className="dropzone">
                  <input {...getInputProps()} />
                  {file ? (
                    <p>Selected: {file.name}</p>
                  ) : (
                    <p>Drag & drop a CSV file here, or click to select</p>
                  )}
                </div>
              )}
            </Dropzone>
          </div>

          <div className="form-group">
            <label>Target Column</label>
            <input
              type="text"
              value={targetColumn}
              onChange={(e) => setTargetColumn(e.target.value)}
              placeholder="e.g., diagnosis"
            />
          </div>

          <div className="form-group">
            <label>Columns to Drop (comma-separated)</label>
            <input
              type="text"
              value={dropColumns}
              onChange={(e) => setDropColumns(e.target.value)}
              placeholder="e.g., id"
            />
          </div>

          <button type="submit" disabled={loading} className="submit-btn">
            {loading ? (
              <span className="spinner">Processing...</span>
            ) : (
              'Run Models'
            )}
          </button>

          {error && <div className="error-message">{error}</div>}
        </form>

        {results && (
          <section className="results-section">
            <h2>Results</h2>
            <table className="results-table">
              <thead>
                <tr>
                  <th>Model</th>
                  <th>Accuracy</th>
                </tr>
              </thead>
              <tbody>
                {accuracies.map((model, index) => (
                  <tr
                    key={index}
                    className={model.name === bestModel ? 'best-model' : ''}
                  >
                    <td>{model.name}</td>
                    <td>
                      {model.accuracy === 'Error' ? (
                        <span className="error-text">Error: {model.error}</span>
                      ) : (
                        `${(model.accuracy * 100).toFixed(2)}%`
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <div className="best-model-summary">
              <strong>Best Model:</strong> {bestModel} with{' '}
              {(bestAccuracy * 100).toFixed(2)}% accuracy
            </div>
          </section>
        )}
      </main>
    </div>
  );
}

export default App;
